    private fun scheduleNextTask(taskId: Int) {
        val calendar = Calendar.getInstance()
        calendar.add(Calendar.MINUTE, taskId * 15)
        val nextExecutionTime = calendar.timeInMillis

        if (System.currentTimeMillis() < nextExecutionTime) {
            startForeground(1, getNotification())
            val intent = Intent(this, MaintenanceService::class.java)
            intent.putExtra("taskType", "sync_data")
            intent.putExtra("taskId", taskId + 1)
            PendingIntent.getBroadcast(this, 0, intent, PendingIntent.FLAG_UPDATE_CURRENT).let { alarmManager.setRepeating(
                AlarmManager.RTC_WAKEUP,
                nextExecutionTime,
                AlarmManager.INTERVAL_HOUR,
                it
